class RateLimiter {
  private redis: Redis;
  private maxRequests: number;
  private windowSeconds: number;

  // Lua script as a string constant
  private readonly ALLOW_SCRIPT = `
    local key = KEYS[1]
    local max_requests = tonumber(ARGV[1])
    local window_seconds = tonumber(ARGV[2])
    local now = redis.call('TIME')
    local current_time = tonumber(now[1]) + tonumber(now[2]) / 1000000
    local window_start = current_time - window_seconds

    -- Remove old entries outside the window
    redis.call('ZREMRANGEBYSCORE', key, 0, window_start)

    -- Count current requests in the window
    local count = redis.call('ZCARD', key)

    if count < max_requests then
      -- Add current timestamp as a new request
      redis.call('ZADD', key, current_time, current_time)
      return {1, current_time, count + 1, window_start + window_seconds}
    else
      return {0, current_time, count, window_start + window_seconds}
    end
  `;

  constructor(redis: Redis, options: RateLimiterOptions) {
    this.redis = redis;
    this.maxRequests = options.maxRequests;
    this.windowSeconds = options.windowSeconds;
  }

  async allow(key: string): Promise<boolean> {
    const result = await this.redis.eval(
      this.ALLOW_SCRIPT,
      1,
      key,
      this.maxRequests,
      this.windowSeconds
    ) as [number, number, number, number];
    return result[0] === 1;
  }

  async remaining(key: string): Promise<number> {
    const now = await this.redis.time();
    const currentTime = now[0] + now[1] / 1000000;
    const windowStart = currentTime - this.windowSeconds;
    await this.redis.zremrangebyscore(key, 0, windowStart);
    const count = await this.redis.zcard(key);
    return Math.max(0, this.maxRequests - count);
  }

  async resetAt(key: string): Promise<number> {
    const now = await this.redis.time();
    const currentTime = now[0] + now[1] / 1000000;
    const windowStart = currentTime - this.windowSeconds;
    return windowStart + this.windowSeconds;
  }
}
