var ErrPoolFull = errors.New("worker pool queue is full")

// ErrPoolClosed is returned by Submit after Shutdown has been called.
var ErrPoolClosed = errors.New("worker pool is closed")

// Stats holds a consistent snapshot of the pool's metrics.
type Stats struct {
	InFlight        int64 // tasks currently being executed
	QueueDepth     int64 // tasks waiting in the queue
	TotalSubmitted int64 // total tasks submitted to the pool
	TotalCompleted int64 // total tasks that have completed (including panics)
	TotalPanics    int64 // total tasks that panicked
	TotalRejected  int64 // total submissions rejected (full or closed)
}

// BoundedWorkerPool is a fixed-size pool of goroutines that execute submitted
// tasks. The pool maintains an internal bounded task queue. If the queue is
// full, Submit returns ErrPoolFull immediately. The pool supports graceful
// shutdown: after Shutdown is called, new submissions are rejected, and the
// pool waits for all in‑flight tasks to finish (or the provided context
// expires). Panics inside a task are recovered, converted to an error, and
// sent on the task's result channel so the worker continues processing.
type BoundedWorkerPool struct {
	// Configuration
	numWorkers int
	queueSize int

	// Internal state
	taskChan chan task        // buffered channel holding pending tasks
	closed   bool            // true after Shutdown has been called
	mu       sync.Mutex       // protects closed flag and ensures consistent Stats snapshot
	wg       sync.WaitGroup  // tracks in‑flight tasks
	statsMu  sync.RWMutex   // serialises access to the Stats snapshot
	stats    Stats           // aggregated counters (written under statsMu)

	// stopChan is closed when the pool is shutting down, signalling workers
	// to exit after they finish their current task.
	stopChan chan struct{}
}

// NewBoundedWorkerPool creates a new pool with w workers and a queue that can
// hold up to q pending tasks. Both w and q must be positive.
func NewBoundedWorkerPool(w, q int) *BoundedWorkerPool {
	if w <= 0 || q <= 0 {
		panic("worker pool: both worker count and queue size must be > 0")
	}
	p := &BoundedWorkerPool{
		numWorkers: w,
		queueSize:  q,
		taskChan:   make(chan task, q),
		stopChan:   make(chan struct{}),
	}
	// Start the fixed set of workers.
	for i := 0; i < w; i++ {
		p.wg.Add(1)
		go p.worker()
	}
	return p
}

// task couples a function to its result channel.
type task struct {
	fn   func() error
	errCh chan<- error
}

// Submit submits a task to the pool. It returns a channel that will
