// worker runs a loop that dequeues tasks and executes them. It recovers from
// any panic raised by a task and sends the panic value as an error on the
// task's result channel. The worker exits when the pool's stop channel is
// closed.
func (p *BoundedWorkerPool) worker() {
	defer p.wg.Done()
	for {
		select {
		case <-p.stopChan:
			// Shutdown has been requested; exit gracefully.
			return
		case t := <-p.taskChan:
			p.addQueueDepth(-1) // one fewer task waiting
			p.addInFlight(1)
			p.executeTask(t)
			p.addInFlight(-1)
